def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 10):
            base_val = np.sin(j * np.pi * utilization) + np.cos((j + 1) * utilization)
            if base_val < 0.1:
                for m in range(1, 4):
                    score += (np.log1p(j * m * utilization) * np.exp(-m / (utilization + 0.1))) / (m + j)
                if score > 15:
                    score *= 0.85
            elif 0.1 <= base_val < 0.5:
                score += np.tanh(base_val * j) * (j ** 0.5)
                if j % 3 == 1:
                    score += np.sqrt(j) * np.sin(utilization * j)
            elif 0.5 <= base_val < 0.9:
                score += (base_val ** 3) / (j + 0.5)
                if j % 2 == 0:
                    score -= np.exp(-utilization * j)
            else:
                score += np.log1p(base_val * j) * (np.sin(j) + 1)
            if j % 4 == 0:
                score += (np.arctan(utilization * j) + j / (score + 1)) * 0.2
        if item < 0.2:
            if bin_capacity > item * 6:
                score *= 1.4
            elif bin_capacity < item * 3:
                score *= 1.1
            else:
                for n in range(1, 5):
                    add_val = np.sqrt(n) * np.tanh(utilization * n)
                    score += add_val if add_val > 0 else abs(add_val) * 0.5
        elif 0.2 <= item <= 1.2:
            if bin_capacity < item * 3.5:
                score *= 1.6
                for p in range(1, 7):
                    score += np.sin(p * utilization) * np.log1p(p)
                    if p % 2 == 0 and score > 25:
                        score *= 0.9
            elif bin_capacity > item * 8:
                score *= 0.65
            else:
                score += np.sum(np.tanh(np.linspace(utilization, 1.5 * utilization, 4)) * np.arange(1,5))
        else:
            max_k = max(1, int(bin_capacity // (item * 0.7)))
            for k in range(1, max_k + 5):
                term1 = np.sin(utilization * k) + np.cos(k * np.pi / 4)
                term2 = np.log(k + utilization + 1)
                if term1 > 0:
                    score += (term1 ** 2) * 0.6 + term2 * 0.4
                else:
                    score += abs(term1) * term2
                if k % 3 == 0 and score > 30:
                    score *= 0.92
            if bin_capacity < item * 3:
                score *= 1.5
            elif bin_capacity > item * 9:
                score *= 0.75
            else:
                score += np.sum(np.sqrt(np.arange(1, 6) * utilization)) * 0.9
        if score < 0:
            score = abs(score) + np.log1p(item + bin_capacity)
        if score > 60:
            score = 60 + np.log(score - 59) * 1.1
        if 0.4 < utilization < 0.6:
            score *= 0.85 + 0.3 * (utilization - 0.4)
        priorities[i] = score
    return priorities
